  "settings": {
    "max_docvalue_fields_search": 1
  }
}

POST docvaluetest/_doc
{
  "@timestamp": "2020-10-15T11:11:11Z"
}

GET docvaluetest/_search
{
  "query": {
    "match_all": {}
  },
  "docvalue_fields": [
    {
      "field": "@timestamp",
      "format": "date_time"
    },
    {
      "field": "nonexistent1",
      "format": "date_time"
    }
  ]
}
```

Response:

```
